{
  "name": "SNAP (Food Stamps)",
  "eligibility": {
    "age": null,
    "income_limits": "Households with an elderly (60+) or disabled member have no gross income limit in Wyoming; only net income limits apply (e.g., for FY2026 Oct 1, 2025–Sept 30, 2026, net income must be below 100% FPL, such as ~$1,255/month for 1 person or ~$1,704 for 2; exact table at dfs.wyo.gov varies by household size). All households must pass net income test after deductions (20% earned income, standard $177–$246 by size, medical >$35 for elderly/disabled, shelter unlimited for elderly/disabled up to $569 otherwise, dependent care, child support). Gross income limit 130% FPL for non-elderly/disabled (~$1,632/1 person); 165% for some. Social Security, pensions count as income.[2][3][4][7]",
    "asset_limits": "Countable resources (bank accounts, cash): $4,500 if household has member 60+ or disabled; $3,000 otherwise (some sources note $3,750 or $2,500—use official $4,500/$3,000). Exempt: home, vehicles, SSI recipients or POWER/Tribal TANF households fully exempt. Residency: Wyoming resident, apply in own county. U.S. citizen or qualified non-citizen.[1][2][3]",
    "other_requirements": ["Must live in Wyoming and apply in county of residence", "Work requirements exempt for 60+, disabled, or unfit (verified by disability benefits, medical pro, etc.)", "Household includes those who buy/prepare food together"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for food purchases at authorized retailers; amount based on net income, household size, deductions (e.g., max allotment for 2-person elderly/disabled: ~$546, minus 30% net income). Exact varies; use calculator for estimate.",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: dfs.wyo.gov/assistance-programs/food-assistance (My Wyoming portal)", "Phone: Local county DFS office (find at dfs.wyo.gov/field-offices)", "Mail/In-person: County Department of Family Services office where you reside", "Apply in county of residence"],
    "processing_time": "Typically 30 days; expedited if very low income (<$150 earned/$100 cash, assets <$100) within 7 days.",
    "waitlist": null,
    "forms": ["SNAP application via My Wyoming online or county office form"],
    "documents": ["Proof of income (pay stubs, Social Security award letters)", "ID/residency proof", "Expense proofs (rent, utilities, medical bills >$35 for elderly/disabled)", "Bank statements for assets", "Disability/age verification if claiming exemptions"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Apply in county of residence",
    "regional_variations": "Administered by local county DFS offices; potential processing/wait differences by county demand, but uniform rules.",
    "offices_or_providers": ["County Department of Family Services offices (list at dfs.wyo.gov/field-offices)"]
  },
  "official_source": "https://dfs.wyo.gov/assistance-programs/food-assistance/supplemental-nutrition-assistance-program-snap",
  "gotchas": ["Elderly/disabled: no gross income limit but still net test + assets; shelter deduction unlimited (key for high medical/housing costs)", "Assets exempt for SSI/POWER recipients—often missed", "Household must include food-sharing members, even non-applicants", "Medical deductions >$35/month critical for seniors", "County-specific application required, not statewide office", "Social Security/pensions count as income", "No gross limit doesn't mean automatic qualify—net calc complex"],
  "data_shape_notes": "Elderly/disabled exemptions (no gross income limit, higher $4,500 assets, unlimited shelter deduction); county-administered with uniform state rules; benefits scale by household size/net income after senior-friendly deductions"
}

{
  "name": "Wyoming Energy Assistance (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income at or below 60% of Wyoming state median income (equivalent to 150% Federal Poverty Level, whichever higher). Specific limits: 1 person $2,985/month; 2 people $3,904/month; 3 people $4,823/month; 4 people $5,741/month; 5 people $6,660/month; 6 people $7,579/month. Annual examples: 2-person household ≤$46,000; 4-person household ≤$68,902. SSI/SNAP recipients may qualify automatically. Priority for elderly (60+), disabled, or children under 6.",
    "asset_limits": "No asset limits mentioned in program requirements.",
    "other_requirements": ["Responsible for home energy costs (homeowners, renters, permanently parked RVs).", "U.S. citizen or eligible immigration status.", "Household includes all at address sharing utility bill."]
  },
  "benefits": {
    "type": "financial",
    "value": "Heating assistance: $49 minimum to $2,176 maximum per season (typical $200-$1,000), paid directly to utility/fuel vendors (natural gas, oil, propane, electricity, wood, pellets, coal). Crisis assistance: up to $550 for emergencies (utility shutoff, empty fuel tanks, broken equipment). No cooling assistance. Weatherization services available separately for efficiency upgrades.",
    "varies_by": "household_size|income|fuel_type|priority_tier"
  },
  "application": {
    "methods": ["Online: lieapwyo.org", "Phone: 1-800-246-4221 (callback system holds place in line)", "Local: Community Action Agency, Area Agency on Aging, or state LIEAP office (phone/mail/in-person for elderly/disabled)"],
    "processing_time": "Payments start Oct. 1 for crisis/disconnection cases; unregulated fuels after Oct. 1. Varies by application volume.",
    "waitlist": "Higher-than-normal applications reported; phone callback system manages demand.",
    "forms": ["No specific form name/number listed; apply via website/phone/local agency"],
    "documents": ["Proof of identity", "Proof of income for all household members (12 months)", "Recent utility bill", "Social Security numbers for household members", "Proof of U.S. citizenship/eligible immigration status"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all Wyoming households (homeowners/renters/RVs)",
    "regional_variations": "Administered statewide by Wyoming Department of Family Services; local agencies (Community Action, Area Agency on Aging) handle applications with potential wait time differences. Three contractors for weatherization.",
    "offices_or_providers": ["Local Community Action Agency", "Area Agency on Aging", "Wyoming Department of Family Services LIEAP office"]
  },
  "official_source": "https://dfs.wyo.gov/assistance-programs/home-utilities-energy-assistance/",
  "gotchas": ["Priority application window until Oct. 1 for elderly 60+, disabled, young children; general applications Oct. 1-April 30 only.", "Heating season focus (Oct-April 2026); no routine cooling assistance.", "Crisis requires immediate emergency proof (shutoff notice, empty tank).", "High application volume causes delays; use callback phone feature.", "Roommates on same utility bill count as one household.", "Federal funds cap at 60% state median income."],
  "data_shape_notes": "Income based on 60% Wyoming state median (varies by household size, listed monthly); priority tiers for elderly/disabled/young kids with early application window; crisis separate from regular heating; statewide but local agency processing; season-limited (2025-2026: now open until April 30, 2026)"
}

{
  "name": "Wyoming State Health Insurance Information Program (WSHIIP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries, families, and caregivers[1][2]",
    "asset_limits": "No asset limits or tests apply[2][5]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver; no other restrictions specified[1][2][4]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free one-on-one health insurance counseling, information and printed materials, referrals to agencies; covers Medicare Parts A/B/D, Medigap, Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, fraud prevention; unbiased, confidential assistance to understand benefits, compare options, resolve issues[1][4][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-856-4398 (toll-free) or (307) 856-6880[4][7][8]", "Website: www.wyomingseniors.com[4][7]", "In-person: Contact via phone for local volunteer counselors in almost every county[4]", "Mail/In-person address: Wyoming Dept of Insurance, 106 West Adams Ave, Riverton WY 82501[3]"],
    "processing_time": "No formal processing; services provided via appointment scheduling upon contact[1][4]",
    "waitlist": null,
    "forms": ["No specific application forms required; intake may occur during counseling[5]"],
    "documents": ["No documents specified; bring Medicare card/ID if available for counseling, but not required to start[1][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Wyoming[3]",
    "regional_variations": "Over 80 volunteers in almost every county provide local counseling; no differences in services noted[4]",
    "offices_or_providers": ["Wyoming Seniors, Inc. (WSCI) administers; local volunteers county-wide; main contact Riverton[3][4]"]
  },
  "official_source": "https://www.wyomingseniors.com/services/wyoming-state-health-insurance-information-program[4]",
  "gotchas": ["Not a financial aid or healthcare payment program—only free counseling and education, no direct benefits or payments; people may confuse it with Medicare Savings Programs it helps apply for; services rely on volunteers, so availability depends on local counselors; must be Medicare-related[1][2][6]"],
  "data_shape_notes": "no income/asset test; volunteer-driven network covering nearly all counties; counseling-only, not benefits-paying; prioritizes limited-income and under-65 disabled but open to all Medicare households[2][4]"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary by household size and are updated annually by the U.S. Department of Health and Human Services; families must contact the local office for the current year's table as specific figures are not listed in sources.",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Resident of Wyoming (statewide or specific counties depending on provider)", "U.S. citizen or authorized to work", "Poor employment prospects (program goal)"]
  },
  "benefits": {
    "type": "employment",
    "value": "Paid part-time community service work training (average 20 hours per week) at the highest of federal, state, or local minimum wage; job placement assistance, resume help, interview skills, and support to transition to unsubsidized employment; training typically lasts 6-12 months.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: (307) 251-1750, (307) 475-6198 (statewide), (307) 473-3968 (Casper/Natrona area)", "In-person: 444 West Collins Drive, Casper, WY 82601 (for Natrona and surrounding counties)", "Email: dws.wyo.gov contact", "Text or call via Wyoming 211", "Website: https://dws.wyo.gov/dws-division/workforce-center-program-operations/programs/senior-community-service-employment-program/"],
    "processing_time": null,
    "waitlist": "Space is limited; waiting lists likely due to limited slots",
    "forms": ["Complete an application at local SCSEP office; no specific form name/number listed"],
    "documents": ["Proof of age (ID)", "Proof of income", "Proof of residency", "Proof of unemployment status", "Social Security number"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Operates in all 23 counties but with specific providers; confirmed in at least 5 counties (Hot Springs, Fremont, Natrona, Washakie, Converse) via Wyoming Department of Workforce Services; other counties via partners like AARP Foundation.",
    "regional_variations": "Different providers and offices by region (e.g., DWS in central Wyoming, potential AARP or others elsewhere); contact state office for county-specific details; no specific wait time variations noted.",
    "offices_or_providers": ["Wyoming Department of Workforce Services (Casper: 444 West Collins Drive, Casper, WY 82601)", "AARP Foundation (oversees in Wyoming)", "Casper Senior Center referral (307-473-3968)"]
  },
  "official_source": "https://dws.wyo.gov/dws-division/workforce-center-program-operations/programs/senior-community-service-employment-program/",
  "gotchas": ["Not available statewide uniformly—must confirm county coverage and provider; limited slots lead to waitlists; priority given to veterans/qualified spouses, then over 65, disabled, rural residents, homeless/at-risk, low literacy, limited English, low prospects, or American Job Center users; income is family-based at 125% FPL (stricter than some programs); goal is bridge to unsubsidized work, not long-term employment; must be unemployed and actively seeking transition."],
  "data_shape_notes": "County-specific providers with limited slots; priority enrollment tiers; income at 125% FPL family basis; not fully statewide uniform operations despite 23-county coverage claim."
}

