{
  "name": "Wyoming Home Services Program",
  "eligibility": {
    "age": 18,
    "income_limits": "No specific income or asset limits mentioned in program documents; financial eligibility not detailed as a barrier. Appears needs-based without dollar thresholds, unlike Medicaid programs.[1][7][8]",
    "asset_limits": "No asset limits specified; no mention of countable assets or exemptions.[1][7][8]",
    "other_requirements": [
      "At risk of premature institutionalization, determined through ongoing evaluation.",
      "Needs in at least 2 areas on Activities of Daily Living (ADL) or Instrumental Activities of Daily Living (IADL) scales (e.g., eating, bathing, housework, shopping).",
      "Exceptions possible if services needed to prevent inappropriate institutional placement even without meeting the 2-area threshold.[1]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Specific in-home services including: Personal care (assistance with eating, dressing, bathing, toileting, transferring, walking); Homemaker services (meal prep, shopping, money management, phone use, light housework); Chore services (heavy housework, yard work, sidewalk maintenance); Respite care (temporary relief for caregivers); Home modification (minor adaptations to facilitate home living). Tailored to individual service plan; no fixed dollar amounts or hours per week specified.[1][6][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Contact local provider: One provider per county (e.g., Campbell County Senior Center In-Home Department; Wyoming Senior Citizens Inc. for Albany/Fremont/Park Counties). Call local senior center or aging office.[5][6]",
      "No statewide online application, phone number, or mail address specified; apply via county-specific Access Care Coordinator (ACC).[1][5]"
    ],
    "processing_time": "Services begin after Service Plan finalized and scheduling; ACC meets every 90 days for ongoing coordination. No exact processing timeline given.[5]",
    "waitlist": "Not mentioned; may vary by county provider capacity.[1]",
    "forms": ["No specific form names or numbers identified."],
    "documents": ["Not explicitly listed; prepare for evaluation of ADLs/IADLs and institutionalization risk. Ongoing assessment required.[1][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available across Wyoming.",
    "regional_variations": "Administered by one designated provider per county (e.g., different senior centers or nonprofits like Wyoming Senior Citizens Inc.); services tailored locally with potential differences in wait times, providers, or availability based on county capacity.[1][5][6][8]",
    "offices_or_providers": ["County-specific: e.g., Campbell County Senior Center, Wyoming Senior Citizens Inc. (Albany/Fremont/Park). Contact local senior services.[5][6]"]
  },
  "official_source": "https://health.wyo.gov/aging/communityliving/community-living-section-programs/wyhs/",
  "gotchas": [
    "Not Medicaid-funded; state grant program with no income/asset tests like Medicaid waivers (e.g., differs from nursing home Medicaid's $2,982/month income limit).[1][2][8]",
    "Priority to those at risk of institutionalization; not automatic for all 18+ with needs.[1][8]",
    "Services exclude handling banking, medications, alcohol/tobacco purchases.[8]",
    "One provider per county—must contact local office, not statewide application.[8]",
    "Minimum 18 years old, not just seniors (includes disabled adults).[1][7]"
  ],
  "data_shape_notes": "County-administered via single provider per county; needs-based without financial limits; services customized per individual plan with priority for institutionalization risk."
}

{
  "name": "Wyoming Senior Companion Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Low-income requirement at or below 200% of federal poverty level (specific dollar amounts not listed in sources; past Wyoming reference to under $42,500 annually, but confirm current levels as they vary by household size and year). Income counted from all sources over past 12 months, including wages, public assistance, pensions, dividends; excludes asset withdrawals, certain medical expenses.[1][2][6]",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Must be healthy and able to volunteer", "Background check including National Service Criminal History Check (NSCHC)", "For volunteers: available to serve 15-40 hours/week, 5-40 hours possible[3][9]"]
  },
  "benefits": {
    "type": "service",
    "value": "Companionship, assistance with daily tasks (shopping, paying bills), friendship, support for frail elderly, disabled adults, terminally ill, or caregivers; volunteers serve 2-4 clients, 15-40 hours/week; volunteer benefits: modest tax-free stipend, transportation reimbursement, meals during service, annual physical, accident/liability insurance, training.[3][6][7]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Contact Wyoming Senior Citizens, Inc. (statewide provider; specific phone/website not in results, check volunteerwyoming.org or health.wyo.gov for current contacts)", "In-person or mail via regional offices like Wyoming State SCP Riverton[3]", "Volunteer application and income verification form (similar to Senior Companion Application)[1]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["VOLUNTEER APPLICATION SENIOR COMPANION PROGRAM", "SCP VOLUNTEER INCOME VERIFICATION FORM", "NATIONAL SERVICE CRIMINAL HISTORY CHECK (NSCHC)"],
    "documents": ["Proof of income (past 12 months)", "Government-issue photo ID for identity verification", "Consent for background check", "Medical info if applicable for stipend eligibility (allowable medical expenses deducted)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; serves homebound across Wyoming",
    "regional_variations": "Administered statewide by Wyoming Senior Citizens, Inc. (WSCI); supports ~90 companions serving 610 clients; possible local offices (e.g., Riverton), but uniform structure[2][3][6][8]",
    "offices_or_providers": ["Wyoming Senior Citizens, Inc. (primary)", "Wyoming State SCP - Riverton"]
  },
  "official_source": "https://health.wyo.gov/ (Wyoming Dept. of Health references program); https://www.volunteerwyoming.org/agency/detail/?agency_id=12577 (Wyoming Senior Citizens, Inc.)",
  "gotchas": ["This is a volunteer program for low-income seniors (55+) to help others, not direct aid to elderly clients—families apply to receive volunteer matches, not personal stipends", "Income eligibility strict for volunteers (200% FPL); clients are frail/homebound but no client income/age test specified", "Stipend tax-free but modest; requires background checks and training commitment", "Not paid caregiving—volunteers provide non-medical support only[1][2][3][6]"],
  "data_shape_notes": "Volunteer stipend program matching low-income seniors (55+) as companions to frail elderly/disabled; statewide via Wyoming Senior Citizens Inc.; income-tested for volunteers only (200% FPL, medical deductions); no client eligibility barriers beyond need; ~90 volunteers statewide"
}
